static async create(document: Document, config: SvelteConfig | undefined) {
    if (!config?.preprocess) {
        return new TranspiledSvelteDocument(document.getText());
    }

    const filename = document.getFilePath() || '';
    const preprocessed = await document.compiler.preprocess(
        document.getText(),
        wrapPreprocessors(config?.preprocess),
        {
            filename
        }
    );

    if (preprocessed.code === document.getText()) {
        return new TranspiledSvelteDocument(document.getText());
    }

    return new TranspiledSvelteDocument(
        preprocessed.code,
        preprocessed.map
            ? new SourceMapDocumentMapper(
                  createTraceMap(preprocessed.map),
                  // The "sources" array only contains the Svelte filename, not its path.
                  // For getting generated positions, the sourcemap consumer wants an exact match
                  // of the source filepath. Therefore only pass in the filename here.
                  getLastPartOfPath(filename)
              )
            : undefined
    );
}

private redirectCallHierarchyItem(
    snapshot: DocumentSnapshot,
    program: ts.Program | undefined,
    item: ts.CallHierarchyItem
): CallHierarchyItem | null {
    if (
        !isSvelteFilePath(item.file) ||
        !program ||
        !(snapshot instanceof SvelteDocumentSnapshot)
    ) {
        return null;
    }

    const sourceFile = program.getSourceFile(item.file);

    if (!sourceFile) {
        return null;
    }

    if (isGeneratedSvelteComponentName(item.name)) {
        return this.toComponentCallHierarchyItem(snapshot, item);
    }

    if (item.name === internalHelpers.renderName) {
        const end = item.selectionSpan.start + item.selectionSpan.length;
        const renderFunction = sourceFile.statements.find(
            (statement) =>
                statement.getStart() <= item.selectionSpan.start && statement.getEnd() >= end
        );

        if (!renderFunction || !sourceFile.statements.includes(renderFunction)) {
            return null;
        }
        return this.toComponentCallHierarchyItem(snapshot, item);
    }

    return null;
}

export function getComponentAtPosition(
    lang: ts.LanguageService,
    doc: Document,
    tsDoc: SvelteDocumentSnapshot,
    originalPosition: Position
): ComponentInfoProvider | null {
    if (tsDoc.parserError) {
        return null;
    }

    if (
        isInTag(originalPosition, doc.scriptInfo) ||
        isInTag(originalPosition, doc.moduleScriptInfo)
    ) {
        // Inside script tags -> not a component
        return null;
    }

    const node = getNodeIfIsInComponentStartTag(doc.html, doc, doc.offsetAt(originalPosition));
    if (!node) {
        return null;
    }

    const symbolPosWithinNode = node.tag?.includes('.') ? node.tag.lastIndexOf('.') + 1 : 0;

    const generatedPosition = tsDoc.getGeneratedPosition(
        doc.positionAt(node.start + symbolPosWithinNode + 1)
    );

    const def = lang.getDefinitionAtPosition(
        tsDoc.filePath,
        tsDoc.offsetAt(generatedPosition)
    )?.[0];
    if (!def) {
        return null;
    }

    return JsOrTsComponentInfoProvider.create(lang, def, tsDoc.isSvelte5Plus);
}

private mapWorkspaceSymbol(
    item: ts.NavigateToItem,
    snapshot: DocumentSnapshot
): WorkspaceSymbol | undefined {
    let location = mapLocationToOriginal(snapshot, convertRange(snapshot, item.textSpan));
    if (location.range.start.line < 0) {
        if (isGeneratedSvelteComponentName(item.name)) {
            location = {
                uri: snapshot.getURL(),
                range: {
                    start: { line: 0, character: 0 },
                    end: { line: 0, character: 1 }
                }
            };
        } else {
            return undefined;
        }
    }

    return {
        kind: this.convertSymbolKindForWorkspaceSymbol(item.kind),
        name: this.getLabel(item),
        containerName:
            snapshot instanceof SvelteDocumentSnapshot &&
            (item.containerName === internalHelpers.renderName || !item.containerName)
                ? isInScript(location.range.start, snapshot)
                    ? 'script'
                    : undefined
                : item.containerName,
        location,
        tags: item.kindModifiers?.includes('deprecated') ? [SymbolTag.Deprecated] : undefined
    };
}

function extractTag(htmlx: string, tag: 'script' | 'style') {
    const exp = tag === 'script' ? scriptRegex : styleRegex;
    const matches: Node[] = [];

    let match: RegExpExecArray | null = null;
    while ((match = exp.exec(htmlx)) != null) {
        if (match[0].startsWith('<!--')) {
            // Tag is inside comment
            continue;
        }

        let content = match[4];
        if (!content) {
            // Keep tag and transform it like a regular element
            content = '';
        }

        const start = match.index + match[2].length;
        const end = start + content.length;
        const containerStart = match.index;
        const containerEnd = match.index + match[0].length;

        matches.push({
            start: containerStart,
            end: containerEnd,
            name: tag,
            type: tag === 'style' ? 'Style' : 'Script',
            attributes: parseAttributes(match[3], containerStart + `<${tag}`.length),
            content: {
                type: 'Text',
                start,
                end,
                value: content,
                raw: content
            }
        });
    }

    return matches;
}

function openTooltip(reason: OpenReason) {
	if (closeTimeout) {
		window.clearTimeout(closeTimeout);
		closeTimeout = null;
	}

	if (!openTimeout) {
		openTimeout = window.setTimeout(() => {
			open.set(true);
			// Don't override the reason if it's already set.
			openReason.update((prev) => prev ?? reason);
			openTimeout = null;
		}, openDelay.get());
	}
}

function closeTooltip(isBlur?: boolean) {
	if (openTimeout) {
		window.clearTimeout(openTimeout);
		openTimeout = null;
	}

	if (isBlur && isMouseInTooltipArea) {
		// Normally when blurring the trigger, we want to close the tooltip.
		// The exception is when the mouse is still in the tooltip area.
		// In that case, we have to set the openReason to pointer, so that
		// it can close when the mouse leaves the tooltip area.
		openReason.set('pointer');
		return;
	}

	if (!closeTimeout) {
		closeTimeout = window.setTimeout(() => {
			open.set(false);
			openReason.set(null);
			if (isBlur) clickedTrigger = false;
			closeTimeout = null;
		}, closeDelay.get());
	}
}

const addToast = (props: AddToastProps<T>) => {
	const propsWithDefaults = {
		closeDelay: closeDelay.get(),
		type: type.get(),
		...props,
	} satisfies AddToastProps<T>;

	const ids = {
		content: generateId(),
		title: generateId(),
		description: generateId(),
	};

	const timeout =
		propsWithDefaults.closeDelay === 0
			? null
			: window.setTimeout(() => {
					removeToast(ids.content);
			  }, propsWithDefaults.closeDelay);

	const getPercentage = () => {
		const { createdAt, pauseDuration, closeDelay, pausedAt } = toast;
		if (closeDelay === 0) return 0;

		if (pausedAt) {
			return (100 * (pausedAt - createdAt - pauseDuration)) / closeDelay;
		} else {
			const now = performance.now();
			return (100 * (now - createdAt - pauseDuration)) / closeDelay;
		}
	};

	const toast = {
		id: ids.content,
		ids,
		...propsWithDefaults,
		timeout,
		createdAt: performance.now(),
		pauseDuration: 0,
		getPercentage,
	} as Toast<T>;

	toastsMap.update((currentMap) => {
		currentMap.set(ids.content, toast);
		return new Map(currentMap);
	});

	return toast;
};

