function mapNewImport(
    change: ts.TextChange,
    snapshot: SvelteSnapshot,
    getBaseIndent: () => string
): ts.TextChange | null {
    const previousLineEnds = getPreviousLineEnds(snapshot.getText(), change.span.start);

    if (previousLineEnds === -1) {
        return null;
    }
    const mappable = snapshot.getOriginalTextSpan({
        start: previousLineEnds,
        length: 0
    });

    if (!mappable) {
        // There might not be any import at all but this is rare enough so ignore for now
        return null;
    }

    const originalText = snapshot.getOriginalText();
    const span = {
        start: originalText.indexOf('\n', mappable.start) + 1,
        length: change.span.length
    };

    const baseIndent = getBaseIndent();
    let newText = baseIndent
        ? change.newText
              .split('\n')
              .map((line) => (line ? baseIndent + line : line))
              .join('\n')
        : change.newText;

    return { span, newText };
}

function handleKeydown(event) {
  const target = event.target;
  if (!(target instanceof Element)) return;
  // Item keydown, or keydown on `node` when the list itself is focused.
  if (target !== node && !target.closest(opts.selector)) return;

  const orientation = opts.orientation ?? "horizontal";
  const horizontal = orientation === "horizontal" || orientation === "both";
  const vertical = orientation === "vertical" || orientation === "both";

  const items = getItems();
  if (items.length === 0) return;

  let index = -1;
  if (
    (horizontal && event.key === "ArrowRight") ||
    (vertical && event.key === "ArrowDown")
  ) {
    index = moveBy(items, 1);
  } else if (
    (horizontal && event.key === "ArrowLeft") ||
    (vertical && event.key === "ArrowUp")
  ) {
    index = moveBy(items, -1);
  } else if (opts.home !== false && event.key === "Home") {
    event.preventDefault();
    index = edge(items, 1);
  } else if (opts.end !== false && event.key === "End") {
    event.preventDefault();
    index = edge(items, -1);
  } else {
    return;
  }

  if (index < 0) return;
  opts.onMove?.(index, event);
  if (opts.focusOnMove) items[index]?.focus();
}

export async function getComponents({
	registryIndex,
	config,
}: {
	registryIndex: Awaited<ReturnType<typeof registry.getRegistryIndex>>;
	config: cliConfig.ResolvedConfig;
}) {
	const dirs = {
		ui: config.resolvedPaths.ui,
		components: config.resolvedPaths.components,
		hooks: config.resolvedPaths.hooks,
	};

	const existingComponents: typeof registryIndex = [];
	for (const dir of Object.values(dirs)) {
		if (!existsSync(dir)) continue;

		const files = await fs.readdir(dir, { withFileTypes: true });
		for (const file of files) {
			if (file.isDirectory()) {
				const item = registryIndex.find((item) => item.name === file.name);
				// is a valid shadcn item
				if (item) existingComponents.push(item);
			}
		}
	}

	// Always offer to update the `utils`
	const utilsItem = registryIndex.find((item) => item.name === "utils");
	if (utilsItem) {
		existingComponents.push(utilsItem);
	}

	return existingComponents;
}

export async function transform(
	opts: TransformOptions,
	transformers: (Transformer | false | undefined)[]
): Promise<TransformerResult> {
	const result = {
		content: opts.content,
		dependencies: new Set<string>(),
		devDependencies: new Set<string>(),
		filePath: opts.filePath,
	};
	for (const transformer of transformers.filter(
		(transformer) => transformer !== undefined && transformer !== false
	)) {
		const { content, dependencies, devDependencies, filePath } = await transformer({
			config: opts.config,
			content: result.content,
			filePath: result.filePath,
			supportedFontMarkers: opts.supportedFontMarkers,
		});
		result.content = content ?? result.content;
		dependencies?.forEach((dep) => result.dependencies.add(dep));
		devDependencies?.forEach((dep) => result.devDependencies.add(dep));
		result.filePath = filePath ?? result.filePath;
	}
	return {
		content: result.content,
		dependencies: Array.from(result.dependencies),
		devDependencies: Array.from(result.devDependencies),
		filePath: result.filePath,
	};
}

create(context) {
	const filename = context.filename;

	// Only apply this rule to files in packages/kit/src/runtime
	const in_runtime = filename.includes(path.join('packages', 'kit', 'src', 'runtime'));

	if (!in_runtime) {
		return {};
	}

	return {
		ImportDeclaration(node) {
			const import_path = node.source.value;

			// Check if this is a relative import
			if (typeof import_path === 'string' && import_path.startsWith('.')) {
				// Resolve the import path relative to the current file
				const current_dir = path.dirname(filename);
				const resolved_path = path.resolve(current_dir, import_path);

				// Check if the resolved path points to src/exports
				const exports_path = path.join('packages', 'kit', 'src', 'exports');

				if (resolved_path.includes(exports_path)) {
					context.report({
						node: node.source,
						messageId: 'noRuntimeToExportsImport'
					});
				}
			}
		}
	};
}

